import L from 'leaflet';
import React from 'react';
import { MapContainer, TileLayer, Marker, Tooltip, useMap } from 'react-leaflet';
import 'leaflet/dist/leaflet.css';
import axios from 'axios';

// --- STYLING OBJECTS ---
// NEW: Centralized styles for better code organization.
const styles = {
  container: { position: 'relative', height: '100vh' },
  map: { height: '100%', width: '100%' },
  busInfoPanel: {
    position: 'absolute', top: '10px', right: '10px', width: '250px',
    background: 'rgba(255, 255, 255, 0.9)', padding: '10px',
    borderRadius: '8px', zIndex: 1000,
  },
  anomalyPanel: {
    position: 'absolute', top: '10px', left: '10px', width: '300px',
    maxHeight: '300px', overflowY: 'auto', background: 'rgba(255, 255, 255, 0.9)',
    padding: '10px', borderRadius: '8px', zIndex: 1000,
  },
  anomalyItem: {
    borderBottom: '1px solid #eee', paddingBottom: '5px',
    marginBottom: '5px', cursor: 'pointer',
  },
  statusOverlay: {
    position: 'absolute', bottom: '20px', left: '10px', zIndex: 1000,
    background: 'rgba(255, 255, 255, 0.9)', padding: '10px 15px',
    borderRadius: '8px', fontWeight: 'bold',
  },
  loadingOverlay: {
    position: 'absolute', top: '50%', left: '50%',
    transform: 'translate(-50%, -50%)', zIndex: 1100,
    background: 'rgba(255, 255, 255, 0.9)', padding: '20px', borderRadius: '8px',
  },
  closeButton: {
    float: 'right', border: 'none', background: 'transparent',
    cursor: 'pointer', fontSize: '16px',
  },
  anomalyText: { margin: 0 }
};

// --- COMPONENTS ---

const TextMarker = ({ text }) => {
  return L.divIcon({
    className: 'custom-icon',
    html: `<div style="font-size: 20px;">${text}</div>`,
  });
};

const BusInfoPanel = ({ bus, onClose }) => {
  if (!bus) return null;
  return (
    <div style={styles.busInfoPanel}>
      <button onClick={onClose} style={styles.closeButton}>âś–</button>
      <h3>Bus Details</h3>
      <p><b>Bus ID:</b> {bus.id}</p>
      <p><b>Route:</b> {bus.route}</p>
      <p><b>Status:</b> {bus.status}</p>
      <p><b>Speed:</b> {bus.speed ? bus.speed.toFixed(1) : 'N/A'} mph</p>
    </div>
  );
};

// NEW: MapPanController component to handle map movement.
const MapPanController = ({ position }) => {
    const map = useMap();
    React.useEffect(() => {
        if (position) {
            map.flyTo(position, 15); // Animate pan and zoom
        }
    }, [position, map]);
    return null;
};

const AnomalyPanel = ({ anomalies, onAnomalyClick }) => {
  if (!anomalies || anomalies.length === 0) return null;
  return (
    <div style={styles.anomalyPanel}>
      <h3 style={{ marginTop: 0 }}>Anomaly Feed</h3>
      {anomalies.slice().reverse().map((anomaly, index) => (
          <div key={index} style={styles.anomalyItem} onClick={() => onAnomalyClick(anomaly.bus_id)}>
            <p style={styles.anomalyText}><b>Type:</b> {anomaly.type}</p>
            <p style={styles.anomalyText}><b>Bus ID:</b> {anomaly.bus_id}</p>
            <p style={styles.anomalyText}><b>Details:</b> {anomaly.details}</p>
          </div>
        ))}
    </div>
  );
};

export default function BusMap() {
  const [buses, setBuses] = React.useState([]);
  const [counts, setCounts] = React.useState({ running_count: 0, ghost_count: 0, anomaly_count: 0 });
  const [selectedBus, setSelectedBus] = React.useState(null);
  const [anomalies, setAnomalies] = React.useState([]);
  // NEW: State for loading, errors, and map panning.
  const [loading, setLoading] = React.useState(true);
  const [error, setError] = React.useState(null);
  const [panToPosition, setPanToPosition] = React.useState(null);

  React.useEffect(() => {
    const fetchData = () => {
      Promise.all([
        axios.get('http://127.0.0.1:8000/buses'),
        axios.get('http://127.0.0.1:8000/anomalies')
      ]).then(([busRes, anomalyRes]) => {
        if (busRes.data && Array.isArray(busRes.data.buses)) {
          const anomalyCount = busRes.data.buses.filter(b => b.has_anomaly).length;
          setBuses(busRes.data.buses);
          setCounts({
            running_count: busRes.data.running_count,
            ghost_count: busRes.data.ghost_count,
            anomaly_count: anomalyCount,
          });
        }
        if (anomalyRes.data && Array.isArray(anomalyRes.data.anomalies)) {
          setAnomalies(anomalyRes.data.anomalies);
        }
        setLoading(false);
      }).catch(err => {
        console.error('Error fetching data:', err);
        setError('Failed to load bus data. Please try again later.');
        setLoading(false);
      });
    };

    fetchData();
    const interval = setInterval(fetchData, 30000);
    return () => clearInterval(interval);
  }, []);

  // NEW: Function to handle clicking on an anomaly.
  const handleAnomalyClick = (busId) => {
    const bus = buses.find(b => b.id === busId);
    if (bus) {
        setSelectedBus(bus);
        setPanToPosition([bus.lat, bus.lon]);
    }
  };

  const getBusMarker = (bus) => {
    if (bus.status === 'Ghost') return 'đź”´';
    if (bus.has_anomaly) return 'đźź ';
    return 'đźź˘';
  };

  if (loading) {
    return <div style={styles.loadingOverlay}>Loading Live Bus Data...</div>;
  }

  if (error) {
    return <div style={styles.loadingOverlay}>{error}</div>;
  }

  return (
    <div style={styles.container}>
      <MapContainer center={[40.7128, -74.006]} zoom={12} style={styles.map}>
        <MapPanController position={panToPosition} />
        <TileLayer
          url="https://cartodb-basemaps-a.global.ssl.fastly.net/light_all/{z}/{x}/{y}{r}.png"
          attribution='&copy; <a href="https://www.openstreetmap.org/">OpenStreetMap</a> &copy; CARTO'
        />

        {Array.isArray(buses) && buses.map((bus) => (
            <Marker
              key={bus.id}
              position={[bus.lat, bus.lon]}
              icon={TextMarker({ text: getBusMarker(bus) })}
              eventHandlers={{ click: () => { setSelectedBus(bus); setPanToPosition(null); } }}
            >
              <Tooltip>Bus ID: {bus.id}</Tooltip>
            </Marker>
          ))}
      </MapContainer>

      <AnomalyPanel anomalies={anomalies} onAnomalyClick={handleAnomalyClick} />
      <BusInfoPanel bus={selectedBus} onClose={() => setSelectedBus(null)} />

      <div style={styles.statusOverlay}>
        đźź˘ Running: {counts.running_count} đź”´ Ghost: {counts.ghost_count} đźź  Anomaly: {counts.anomaly_count}
      </div>
    </div>
  );
}
